fn solve(prices: Vec<i64>, strategy: Vec<i64>, k: i64) -> i64 {
    let n = prices.len();
    let original_profit: i64 = strategy.iter().enumerate().map(|(i, &s)| s * prices[i]).sum();

    let m = k / 2;
    let mut A = vec![0; n];
    let mut B = vec![0; n];

    for i in 0..n {
        A[i] = -strategy[i] * prices[i];
        B[i] = (1 - strategy[i]) * prices[i];
    }

    let mut prefixA = vec![0; n + 1];
    let mut prefixB = vec![0; n + 1];

    for i in 0..n {
        prefixA[i + 1] = prefixA[i] + A[i];
        prefixB[i + 1] = prefixB[i] + B[i];
    }

    let mut max_gain = 0;
    let max_i = n as i64 - k;

    for i in 0..=max_i as usize {
        let start = i;
        let sumA = prefixA[start + (m as usize)] - prefixA[start];
        let sumB = prefixB[start + (k as usize)] - prefixB[start + (m as usize)];
        let gain = sumA + sumB;
        if gain > max_gain {
            max_gain = gain;
        }
    }

    original_profit + max_gain.max(0)
}
