fn solve(prices: Vec<i64>, strategy: Vec<i64>, k: i64) -> i64 {
    let n = prices.len();
    let mut original_profit = 0;
    for i in 0..n {
        original_profit += strategy[i] * prices[i];
    }

    let m = k / 2;
    let mut A = vec![0; n];
    let mut B = vec![0; n];
    for i in 0..n {
        A[i] = -strategy[i] * prices[i];
        B[i] = (1 - strategy[i]) * prices[i];
    }

    let mut prefixA = vec![0; n + 1];
    let mut prefixB = vec![0; n + 1];
    for i in 0..n {
        prefixA[i + 1] = prefixA[i] + A[i];
        prefixB[i + 1] = prefixB[i] + B[i];
    }

    let mut max_gain = 0;
    let max_i = n - k;
    for i in 0..=max_i {
        let sumA = prefixA[i + m] - prefixA[i];
        let sumB = prefixB[i + k] - prefixB[i + m];
        let gain = sumA + sumB;
        if gain > max_gain {
            max_gain = gain;
        }
    }

    original_profit + std::cmp::max(0, max_gain)
}
